def get_median(list1, list2, n):
    # Combine both lists and convert them to a min-heap
    combined = list(heapq.merge(list1, list2))

    # Calculate the median based on the length of the combined list
    if n % 2 != 0:
        return combined[n // 2]
    else:
        return (combined[n // 2 - 1] + combined[n // 2]) / 2.0

def get_median(a, b, n):
    def binary_search(low, high):
        while low < high:
            mid = (low + high) // 2
            if a[mid] < b[mid]:
                low = mid + 1
            else:
                high = mid
        return low

    pivot_a = binary_search(0, n - 1)
    pivot_b = n - pivot_a - 1

    if pivot_a == 0:
        max_of_left = b[pivot_b - 1]
    elif pivot_b == 0:
        max_of_left = a[pivot_a - 1]
    else:
        max_of_left = max(a[pivot_a - 1], b[pivot_b - 1])

    if (n % 2 == 1):
        return max_of_left

    if pivot_a == n:
        min_of_right = b[pivot_b]
    elif pivot_b == n:
        min_of_right = a[pivot_a]
    else:
        min_of_right = min(a[pivot_a], b[pivot_b])

    return (max_of_left + min_of_right) / 2

