def maxAverageOfPath(mat):
    N = len(mat)
    dp = [[0] * N for _ in range(N)]
    dp[0][0] = mat[0][0]

    # Fill the first row and first column
    for i in range(1, N):
        dp[i][0] = dp[i - 1][0] + mat[i][0]
        dp[0][i] = dp[0][i - 1] + mat[0][i]

    # Fill the rest of the dp array
    for i in range(1, N):
        for j in range(1, N):
            dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]) + mat[i][j]

    # Calculate the maximum average
    max_avg = -float('inf')
    for i in range(N):
        for j in range(N):
            total_sum = dp[N - 1][j] + dp[i][N - 1] - dp[i][j] - dp[N - 1][N - 1]
            if total_sum != 0:
                max_avg = max(max_avg, total_sum / (N + N - i - j - 2))

    return max_avg

