import numpy as np

def rgb_to_hsv(R, G, B):
    R, G, B = np.array([R]), np.array([G]), np.array([B])
    R /= 255
    G /= 255
    B /= 255

    max_c = np.max(R, G, B)
    min_c = np.min(R, G, B)

    C = max_c - min_c

    if max_c == min_c:
        H = 0
    elif max_c == R:
        H = (60 * ((G - B) / C)) % 360
    elif max_c == G:
        H = (60 * ((B - R) / C)) + 120
    else:
        H = (60 * ((R - G) / C)) + 240

    V = max_c

    if C == 0:
        S = 0
    else:
        S = (C / V) * 100

    return H, S, V

def rgb_to_hsv(R, G, B):
    # Convert RGB values to HSV using the formulae
    if R > G and R > B:
        max_c = R
    elif G > R and G > B:
        max_c = G
    else:
        max_c = B

    min_c = min(R, G, B)

    delta = max_c - min_c

    if max_c == 0:
        H = 0
    elif max_c == R:
        H = (60 * ((G - B) / delta) + 360) % 360
    elif max_c == G:
        H = (60 * ((B - R) / delta) + 120) % 360
    else:
        H = (60 * ((R - G) / delta) + 240) % 360

    V = max_c / 255.0
    if max_c == 0:
        S = 0
    else:
        S = (delta / max_c) * 100

    return H, S, V

def rgb_to_hsv(r, g, b):
    r, g, b = r / 255.0, g / 255.0, b / 255.0
    mx = max(r, g, b)
    mn = min(r, g, b)
    df = mx - mn

    if mx == mn:
        h = 0
    elif mx == r:
        h = (60 * ((g - b) / df) + 360) % 360
    elif mx == g:
        h = (60 * ((b - r) / df) + 120) % 360
    else:
        h = (60 * ((r - g) / df) + 240) % 360

    if mx == 0:
        s = 0
    else:
        s = (df / mx) * 100

    v = mx * 100
    return h, s, v

def rgb_to_hsv(r, g, b):
    if r == g == b: return (0, 0.0, 100.0)
    cmax = max(r, g, b)
    cmin = min(r, g, b)
    diff = cmax - cmin
    if cmax == cmin: return (0, 0.0, 100.0)
    if cmax == r:
        h = (60 * ((g - b) / diff) + 360) % 360
    elif cmax == g:
        h = (60 * ((b - r) / diff) + 120) % 360
    else:
        h = (60 * ((r - g) / diff) + 240) % 360
    s = (diff / cmax) * 100
    v = cmax * 100
    return (h, s, v)

def rgb_to_hsv(R, G, B):
    if R == G == B:
        return (0, 0.0, 100.0)
    else:
        cmax = max(R, G, B)
        cmin = min(R, G, B)
        diff = cmax - cmin
        if cmax == cmin:
            h = 0.0
        elif cmax == R:
            h = 60 * ((G - B) / diff) % 360
        elif cmax == G:
            h = 60 * ((B - R) / diff) + 120
        elif cmax == B:
            h = 60 * ((R - G) / diff) + 240
        s = (diff / cmax) * 100 if cmax != 0 else 0
        v = cmax * 100
        return (h, s, v)

