    r, g, b = r / 255.0, g / 255.0, b / 255.0
    mx = max(r, g, b)
    mn = min(r, g, b)
    df = mx - mn
    if mx == mn:
        h = 0
    elif mx == r:
        h = (60 * ((g - b) / df)) % 360
    elif mx == g:
        h = (60 * ((b - r) / df)) + 120
    else:
        h = (60 * ((r - g) / df)) + 240
    s = 0 if mx == 0 else (df / mx) * 100
    v = mx * 100
    return h, s, v

