def get_median(arr1, arr2, n):
    if len(arr1) != len(arr2) or n != len(arr1):
        raise ValueError("Lists must be of the same size")

    i = 0
    j = 0
    m1 = -1
    m2 = -1

    # Traverse both arrays till mid size and
    # find the median
    while i < n:
        # Compare first elements of both arrays
        if arr1[i] < arr2[j]:
            # If i is odd, then median will be
            # average of previous two medians
            if (n + i) % 2 == 0:
                m1, m2 = m2, max(m1, arr1[i])
            else:
                m1 = max(m1, arr1[i])
            i += 1
        else:
            # If i is odd, then median will be
