        if (n + i) % 2 == 0:
            m1, m2 = m2, max(m1, arr2[j])
        else:
            m1 = max(m1, arr2[j])
        j += 1

    # If first array becomes empty
    # Take median of two medians calculated above
    return (m1 + m2) / 2

def get_median(A, B, n):
    # Initialize pointers for both arrays
    i = j = 0

    # Traverse both arrays until one reaches the end
    while i < n and j < n:
        if A[i] <= B[j]:
            # If current element of A is less than or equal to B, move to next element in A
            i += 1
        else:
            # If current element of B is less than A, move to next element in B
            j += 1

    # If A has more elements than B
    if i < n:
        # Add remaining elements of A to the end of B
        B.extend(A[i:])
    else:
        # Add remaining elements of B to the end of A
        A.extend(B[j:])

    # Calculate median
    mid = (n - 1) // 2

    # If total number of elements is odd, return the middle element
    if (n % 2 != 0):
        return float(A[mid])
    else:
        # If total number of elements is even, return the average of middle two elements
        return (A[mid] + A[mid + 1]) / 2.0

