    R, G, B = R / 255.0, G / 255.0, B / 255.0
    mx = max(R, G, B)
    mn = min(R, G, B)
    diff = mx - mn
    if mx == mn:
        H = 0
    elif mx == R:
        H = (60 * ((G - B) / diff)) % 360
    elif mx == G:
        H = (60 * ((B - R) / diff)) + 120
    else:  # mx == B
        H = (60 * ((R - G) / diff)) + 240
    if mx == 0:
        S = 0
    else:
        S = (diff / mx) * 100
    V = mx * 100
    return int(H), round(S, 2), round(V, 2)

