def maxAverageOfPath(matrix):
    def dfs(x, y):
        if x == n - 1 and y == n - 1:
            return matrix[x][y]

        down = float('-inf')
        right = float('-inf')

        if x + 1 < n:
            down = dfs(x + 1, y)
        if y + 1 < n:
            right = dfs(x, y + 1)

        return max(down, right) + matrix[x][y]

    n = len(matrix)
    total_cost = dfs(0, 0)
    max_average = total_cost / (n * n)
    return max_average

