def get_pairs_count(arr, sum):
    arr.sort()  # Sort the array to optimize the search
    left, right = 0, len(arr) - 1
    count = 0
    while left < right:
        current_sum = arr[left] + arr[right]
        if current_sum == sum:
            count += right - left
            left += 1  # Move the left pointer to the right to find more pairs
        elif current_sum < sum:
            left += 1
        else:
            right -= 1
    return count

