def rgb_to_hsv(R, G, B):
    min_rgb = min(R, G, B)
    max_rgb = max(R, G, B)
    delta = max_rgb - min_rgb

    if delta == 0:
        H = 0
    elif max_rgb == R:
        H = (60 * ((G - B) / delta)) % 360
    elif max_rgb == G:
        H = (60 * ((B - R) / delta)) + 120
    else:  # max_rgb == B
        H = (60 * ((R - G) / delta)) + 240

    S = (delta / max_rgb) * 100
    V = max_rgb * 100

    return (H, S, V)

