def count_rotation(arr):
    n = len(arr)
    if n == 0:
        return 0
    start, end = 0, n - 1
    while start < end:
        mid = (start + end) // 2
        if arr[mid] > arr[end]:
            start = mid + 1
        else:
            end = mid
    return start

